import pickle, collections
from collections import deque

d = pickle.load(open('/tmp/parsed.pkl','rb'))
orders, deliv, wseq, sinfo = d['orders'], d['deliv'], d['wseq'], d['sinfo']

NDAYS = 365
PRODUCTS = [f'P_{i}' for i in range(1,31)]
STORES = [f'S_{i}' for i in range(1,11)]

# Pre-index producer deliveries per (day) ordered by wholesaler sequence
# deliv_by_day[d] = list of (seq, pr, items) sorted by seq
deliv_by_day = collections.defaultdict(list)
for (day, pr), items in deliv.items():
    seq = wseq[(day, pr)]
    deliv_by_day[day].append((seq, pr, items))
for day in deliv_by_day:
    deliv_by_day[day].sort()

# store order per day sorted by store sequence
store_order_by_day = collections.defaultdict(list)
for day in range(1, NDAYS+1):
    lst = []
    for s in STORES:
        seq = sinfo[(day, s)][0]
        lst.append((seq, s))
    lst.sort()
    store_order_by_day[day] = lst

def run_alloc(same_day=True):
    # per-product FIFO queue of [producer, qty_remaining]
    queues = {p: deque() for p in PRODUCTS}
    alloc = {}  # (day,store,product) -> list of (producer, qty)
    store_total = collections.Counter()  # (day,store) -> total delivered
    pending = None  # for next-day model
    for day in range(1, NDAYS+1):
        # 1. add this day's deliveries (ordered by seq)
        if same_day:
            for seq, pr, items in deliv_by_day[day]:
                for p, q in items.items():
                    if q>0:
                        queues[p].append([pr, q])
        else:
            # add yesterday's pending
            if pending is not None:
                for seq, pr, items in pending:
                    for p, q in items.items():
                        if q>0:
                            queues[p].append([pr, q])
            pending = deliv_by_day[day]
        # 2. fulfill stores in sequence order
        for seq, s in store_order_by_day[day]:
            ord_items = orders.get((day, s), {})
            for p, want in ord_items.items():
                want = int(want)
                q = queues[p]
                got = []
                while want > 0 and q:
                    batch = q[0]
                    take = min(want, batch[1])
                    got.append((batch[0], take))
                    batch[1] -= take
                    want -= take
                    if batch[1] == 0:
                        q.popleft()
                if got:
                    # merge consecutive same producer
                    merged = []
                    for pr, qty in got:
                        if merged and merged[-1][0]==pr:
                            merged[-1] = (pr, merged[-1][1]+qty)
                        else:
                            merged.append((pr, qty))
                    alloc[(day, s, p)] = merged
                    store_total[(day, s)] += sum(x[1] for x in merged)
    return alloc, store_total, queues

for same_day in (True, False):
    alloc, store_total, queues = run_alloc(same_day)
    # validate checksum
    mism = 0; total_units_alloc=0; total_units_recv=0
    examples=[]
    for (day, s), (seq, tot) in sinfo.items():
        got = store_total.get((day, s), 0)
        total_units_alloc += got; total_units_recv += tot
        if got != tot:
            mism += 1
            if len(examples)<10: examples.append((day,s,got,tot))
    leftover = sum(sum(b[1] for b in q) for q in queues.values())
    print(f'same_day={same_day}: mismatches={mism}/3650, alloc_total={total_units_alloc}, recv_total={total_units_recv}, leftover_in_wh={leftover}')
    if examples: print('  examples (day,store,got,expected):', examples)
    if same_day and mism==0:
        with open('/tmp/alloc.pkl','wb') as f:
            pickle.dump(dict(alloc=alloc), f)
        print('  saved alloc.pkl')

