import pandas as pd, numpy as np, pickle, collections
g=pd.read_pickle('/tmp/agg.pkl')
consume=pickle.load(open('/tmp/consume.pkl','rb'))['consume']
RR=pickle.load(open('/tmp/resid.pkl','rb'))
R=RR['resid']
NDAYS=365
STORES=[f'S_{i}' for i in range(1,11)]
PRODUCTS=[f'P_{i}' for i in range(1,31)]
K=np.array([0.8]*3+[0.5]*4+[0.2]*7); Wsum=K.sum()
sold={}
for r in g.itertuples(index=False):
    sold[(r.Day,r.Store_ID,r.Product_ID)]=r.sold

resid_np={(P,s):R[P][s].values for P in PRODUCTS for s in STORES}

# For each (P,PR): collect solo days (only producer consumed that store-day) and dominant(>=0.7) days
solo=collections.defaultdict(list)      # (P,pr)->[(s,D0,qty)]
dom =collections.defaultdict(list)
for (day,s,P),lst in consume.items():
    tot=sold.get((day,s,P),0)
    if tot<=0: continue
    if len(lst)==1:
        solo[(P,lst[0][0])].append((s,day,lst[0][1]))
    # dominant single producer
    big=max(lst,key=lambda z:z[1])
    if big[1]/tot>=0.7 and len(lst)>=1:
        dom[(P,big[0])].append((s,day,big[1]))

def post_deficit(events):
    # template-weighted mean deficit over D0+1..D0+14 across events
    num=0.0; den=0.0; tw=0.0; twn=0.0
    for s,D0,q in events:
        arr=resid_np[(P,s)]
        for j in range(1,15):
            di=D0-1+j
            if di<NDAYS and not np.isnan(arr[di]):
                num+=(1.0-arr[di])*K[j-1]; den+=K[j-1]
    return (num/den) if den>0 else np.nan

# baseline deficit per (P,s): overall mean deficit (to subtract local level)
basedef={}
for P in PRODUCTS:
    for s in STORES:
        arr=resid_np[(P,s)]
        basedef[(P,s)]=np.nanmean(1.0-arr)

def post_deficit_adj(events):
    vals=[]; ws=[]
    for s,D0,q in events:
        arr=resid_np[(P,s)]
        acc=0.0; w=0.0
        for j in range(1,15):
            di=D0-1+j
            if di<NDAYS and not np.isnan(arr[di]):
                acc+=(1.0-arr[di])*K[j-1]; w+=K[j-1]
        if w>0:
            vals.append(acc/w - basedef[(P,s)])  # excess deficit over baseline
            ws.append(1)
    if not vals: return np.nan,0
    return float(np.mean(vals)), len(vals)

print(f"{'P':5s} {'PR':6s} {'nsolo':>5s} {'solo_excess':>11s} {'ndom':>5s} {'dom_excess':>10s}")
fin=pickle.load(open('/tmp/final.pkl','rb'))
rows=[]
for P in PRODUCTS:
    d=fin['real'][P]
    for pr,c,dr in sorted(zip(d['active'],d['coef'],d['drops']),key=lambda z:-z[2]):
        if dr<1e-4 and c<1e-4: continue
        se,ns=post_deficit_adj(solo[(P,pr)]) if solo.get((P,pr)) else (np.nan,0)
        de,nd=post_deficit_adj(dom[(P,pr)]) if dom.get((P,pr)) else (np.nan,0)
        rows.append((P,pr,c,dr,ns,se,nd,de))
        if dr>0.02 or (se==se and se>0.03):
            print(f'{P:5s} {pr:6s} {ns:5d} {se if se==se else float("nan"):11.4f} {nd:5d} {de if de==de else float("nan"):10.4f}  coef={c:.3f} udrop={dr:.4f}')
pickle.dump(rows, open('/tmp/soloday.pkl','wb'))

